<?phpnamespace App\Http\Controllers\Api\Auth\Rider;use App\{    Models\Rider,    Models\Notification,    Classes\GeniusMailer,    Models\Generalsetting,    Http\Controllers\Controller};use Illuminate\Http\Request;use Auth;use Validator;use Illuminate\Support\Str;use Illuminate\Support\Facades\Hash;use Illuminate\Support\Facades\DB;use App\Http\Resources\RiderResource;class RiderAuthController extends Controller{//     public function login(Request $request)// {//     try {//         $rules = [//             'email'    => 'required|email',//             'password' => 'required'//         ];//         $request->validate($rules);//         $credentials = request(['email', 'password']);//         if (!$token = auth('rider-api')->setTTL(43200)->attempt($credentials)) {//             return response()->json(['status' => false, 'message' => 'Invalid credentials'], 401);//         }//         $rider = auth('rider-api')->user();//         if ($rider->email_verify == 'No') {//             auth('rider-api')->logout();//             return response()->json(['status' => false, "message" => 'Your Email is not Verified!'], 403);//         }//         if ($rider->rider_status != 'accepted') {//             auth('rider-api')->logout();//             return response()->json([//                 'status' => false,//                 'message' => 'Please wait for admin approval.'//             ], 402);//         }//         return response()->json(['status' => true, 'message' => 'Login successful', 'data' => ['token' => $token, 'rider_type' => $rider->rider_type,         //         // 'rider' => new RiderResource(auth('rider-api')->user())        //         $rider = auth('rider-api')->user()->load('serviceAreas');//         return response()->json([//             'status' => true,//             'message' => 'Login successful',//             'data' => [//                 'token' => $token,//                 'rider_type' => $rider->rider_type,//                 'rider' => new \App\Http\Resources\RiderResource($rider)//             ]//         ]);//         ]]);//         // return response()->json([//         //     'status' => true,//         //     'message' => 'Login successful',//         //     'data' => [//         //         'token' => $token,//         //         'rider_type' => $rider->rider_type,//         //         'rider' => new RiderResource($rider)//         //     ]//         // ]);//     } catch (\Exception $e) {//         return response()->json(['status' => false, 'message' => $e->getMessage()]);//     }// }public function login(Request $request){    try {        $rules = [            'email'    => 'required|email',            'password' => 'required'        ];        $request->validate($rules);        $credentials = $request->only(['email', 'password']);        if (!$token = auth('rider-api')->setTTL(43200)->attempt($credentials)) {            return response()->json([                'status' => false,                'message' => 'Invalid credentials'            ], 401);        }        $rider = auth('rider-api')->user();        if ($rider->email_verify == 'No') {            auth('rider-api')->logout();            return response()->json([                'status' => false,                "message" => 'Your Email is not Verified!'            ], 403);        }        if ($rider->rider_status != 'accepted') {            auth('rider-api')->logout();            return response()->json([                'status' => false,                'message' => 'Please wait for admin approval.'            ], 402);        }        $rider = $rider->load('serviceAreas');        return response()->json([            'status' => true,            'message' => 'Login successful',            'data' => [                'token' => $token,                'rider_type' => $rider->rider_type,                'rider' => new \App\Http\Resources\RiderResource($rider)            ]        ]);    } catch (\Exception $e) {        return response()->json([            'status' => false,            'message' => $e->getMessage()        ]);    }}    public function logout()    {        auth('rider-api')->logout();        return response()->json(['status' => true, 'message' => 'Logout successfully']);    }    public function forgotPassword(Request $request)    {        $request->validate(['email' => 'required|email']);        $gs = Generalsetting::findOrFail(1);        $rider = Rider::where('email', $request->email)->first();        if (!$rider) {            return response()->json(['status' => false, 'message' => 'Account not found!'], 401);        }        DB::table('otp_codes')->where('user_id', $rider->id)->delete();        $otp = $this->createOtp($rider);        $subject = "Reset Password Request";        $msg = "Your Forgot Password OTP: " . $otp;        if ($gs->is_smtp == 1) {            $data = ['to'=>$request->email,'subject'=>$subject,'body'=>$msg];            (new GeniusMailer())->sendCustomMail($data);        } else {            $headers = "From: {$gs->from_name} <{$gs->from_email}>";            mail($request->email, $subject, $msg, $headers);        }        return response()->json(['status' => true, 'message' => 'OTP sent successfully']);    }    public function verifyOtp(Request $request)    {        $request->validate([            'email' => 'required|email',            'otp'   => 'required'        ]);        $rider = Rider::where('email', $request->email)->first();        if(!$rider){            return response()->json(['status' => false, 'message' => 'Invalid email'], 401);        }        $otpRecord = DB::table('otp_codes')            ->where('user_id', $rider->id)            ->where('otp', $request->otp)            ->where('expires_at', '>', now())            ->orderByDesc('id')            ->first();        if (!$otpRecord) {            return response()->json(['status' => false, 'message' => 'Invalid or expired OTP'], 401);        }        return response()->json([            'status' => true,            'message' => 'OTP verified successfully',        ]);    }    public function resetPassword(Request $request)    {        $request->validate([            'email'    => 'required|email',            'otp'      => 'required',            'password' => 'required|min:6|confirmed',        ]);        $rider = Rider::where('email', $request->email)->first();        if (!$rider) {            return response()->json(['status' => false, 'message' => 'Invalid email'], 404);        }        $otpRecord = DB::table('otp_codes')            ->where('user_id', $rider->id)            ->where('otp', $request->otp)            ->where('expires_at', '>', now())            ->orderByDesc('id')            ->first();        if (!$otpRecord) {            return response()->json(['status' => false, 'message' => 'Invalid or expired OTP'], 404);        }        $rider->password = Hash::make($request->password);        $rider->save();        DB::table('otp_codes')->where('id', $otpRecord->id)->delete();        return response()->json([            'status'  => true,            'message' => 'Password reset successfully'        ]);    }    protected function createOtp(Rider $rider)    {        $otp = rand(100000, 999999);        DB::table('otp_codes')->insert([            'user_id'    => $rider->id,            'otp'        => $otp,            'expires_at' => now()->addMinutes(10),        ]);        return $otp;    }}